const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

// Configuration
const DATA_DIR = path.join(__dirname, '../data');
const RAW_JSON = path.join(DATA_DIR, 'shopify-leads-raw.json');
const CSV_OUTPUT = path.join(DATA_DIR, 'shopify-plus-leads.csv');
const REPORT_OUTPUT = path.join(DATA_DIR, 'scraping-report.md');
const SCREENSHOTS_DIR = path.join(DATA_DIR, 'screenshots');

// State tracking
const results = {
  leads: [],
  errors: [],
  stats: {
    builtwith: { attempted: true, success: 0, errors: 0 },
    appStore: { attempted: true, success: 0, errors: 0 },
    enrichment: { attempted: 0, success: 0, errors: 0 }
  }
};

// Helper functions
function log(message) {
  console.log(`[${new Date().toISOString()}] ${message}`);
}

function addLead(domain, source, data = {}) {
  const existing = results.leads.find(l => l.domain === domain);
  if (existing) {
    Object.assign(existing, data);
    if (!existing.sources.includes(source)) {
      existing.sources.push(source);
    }
  } else {
    results.leads.push({
      domain,
      sources: [source],
      brandName: '',
      category: '',
      active: 'Unknown',
      notes: '',
      ...data
    });
  }
}

function addError(source, message, details = '') {
  results.errors.push({
    source,
    message,
    details,
    timestamp: new Date().toISOString()
  });
  log(`ERROR [${source}]: ${message}`);
}

// 1. Scrape BuiltWith
async function scrapeBuiltWith(browser) {
  log('Starting BuiltWith scraping...');
  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
  });
  const page = await context.newPage();

  try {
    log('Navigating to BuiltWith Shopify Plus page...');
    await page.goto('https://builtwith.com/shopify-plus', { 
      waitUntil: 'domcontentloaded',
      timeout: 30000 
    });

    // Take screenshot on arrival
    await page.screenshot({ 
      path: path.join(SCREENSHOTS_DIR, 'builtwith-arrival.png'),
      fullPage: true 
    });
    log('Screenshot saved: builtwith-arrival.png');

    // Wait a bit for content to load
    await page.waitForTimeout(3000);

    // Try multiple selectors for domains/links
    const domains = await page.evaluate(() => {
      const results = new Set();

      // Try common selectors for domain listings
      const selectors = [
        'a[href*="//"]',
        '.domain',
        '.site',
        'td a',
        '.company a',
        '[class*="domain"]',
        '[class*="website"]'
      ];

      selectors.forEach(selector => {
        document.querySelectorAll(selector).forEach(el => {
          let text = el.textContent?.trim();
          let href = el.href;

          // Extract domain from href
          if (href && (href.includes('http://') || href.includes('https://'))) {
            try {
              const url = new URL(href);
              if (!url.hostname.includes('builtwith.com')) {
                results.add(url.hostname.replace('www.', ''));
              }
            } catch (e) {}
          }

          // Extract domain from text
          if (text && text.includes('.')) {
            const domainMatch = text.match(/([a-z0-9-]+\.[a-z]{2,})/i);
            if (domainMatch) {
              results.add(domainMatch[1].replace('www.', ''));
            }
          }
        });
      });

      return Array.from(results);
    });

    log(`Found ${domains.length} potential domains from BuiltWith`);

    if (domains.length === 0) {
      addError('BuiltWith', 'No domains found - may be blocked or page structure changed');
      results.stats.builtwith.errors++;

      // Save page content for debugging
      const content = await page.content();
      fs.writeFileSync(path.join(DATA_DIR, 'builtwith-debug.html'), content);
      log('Saved page content to builtwith-debug.html for debugging');
    } else {
      domains.forEach(domain => {
        addLead(domain, 'BuiltWith');
      });
      results.stats.builtwith.success = domains.length;
    }

  } catch (error) {
    addError('BuiltWith', 'Failed to scrape', error.message);
    results.stats.builtwith.errors++;
  } finally {
    await context.close();
  }
}

// 2. Scrape Shopify App Store
async function scrapeAppStore(browser, appName, appSlug) {
  log(`Scraping Shopify App Store for ${appName}...`);
  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
  });
  const page = await context.newPage();

  try {
    const url = `https://apps.shopify.com/${appSlug}`;
    log(`Navigating to ${url}...`);

    await page.goto(url, { 
      waitUntil: 'domcontentloaded',
      timeout: 30000 
    });

    await page.waitForTimeout(2000);

    // Take screenshot
    await page.screenshot({ 
      path: path.join(SCREENSHOTS_DIR, `appstore-${appSlug}.png`),
      fullPage: false 
    });

    // Scroll to load reviews
    await page.evaluate(() => window.scrollTo(0, document.body.scrollHeight));
    await page.waitForTimeout(2000);

    // Extract store URLs from reviews
    const stores = await page.evaluate(() => {
      const results = new Set();

      // Look for store names/URLs in review sections
      const selectors = [
        '[class*="review"] a[href*=".myshopify.com"]',
        '[class*="review"] a[href*="//"]',
        'a[href*=".myshopify.com"]',
        '.reviewer a',
        '[class*="store"] a'
      ];

      selectors.forEach(selector => {
        document.querySelectorAll(selector).forEach(el => {
          const href = el.href;
          if (href && (href.includes('http://') || href.includes('https://'))) {
            try {
              const url = new URL(href);
              const hostname = url.hostname.replace('www.', '');
              // Filter out Shopify's own domains
              if (!hostname.includes('shopify.com') || hostname.includes('.myshopify.com')) {
                results.add(hostname);
              }
            } catch (e) {}
          }
        });
      });

      return Array.from(results);
    });

    log(`Found ${stores.length} stores from ${appName}`);

    if (stores.length === 0) {
      addError('AppStore', `No stores found for ${appName}`, 'Reviews may not be visible or page structure changed');
      await page.screenshot({ 
        path: path.join(SCREENSHOTS_DIR, `appstore-${appSlug}-noresults.png`),
        fullPage: true 
      });
    } else {
      stores.forEach(domain => {
        addLead(domain, `AppStore-${appName}`);
      });
      results.stats.appStore.success += stores.length;
    }

  } catch (error) {
    addError('AppStore', `Failed to scrape ${appName}`, error.message);
    results.stats.appStore.errors++;
  } finally {
    await context.close();
  }
}

// 3. Alternative: Scrape from general Shopify app lists
async function scrapeShopifyShowcase(browser) {
  log('Scraping Shopify showcase/examples...');
  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
  });
  const page = await context.newPage();

  try {
    // Try Shopify's examples page
    await page.goto('https://www.shopify.com/examples', { 
      waitUntil: 'domcontentloaded',
      timeout: 30000 
    });

    await page.waitForTimeout(2000);
    await page.screenshot({ 
      path: path.join(SCREENSHOTS_DIR, 'shopify-examples.png')
    });

    const stores = await page.evaluate(() => {
      const results = new Set();
      document.querySelectorAll('a[href*="//"]').forEach(el => {
        try {
          const url = new URL(el.href);
          const hostname = url.hostname.replace('www.', '');
          if (!hostname.includes('shopify.com') || hostname.includes('.myshopify.com')) {
            results.add(hostname);
          }
        } catch (e) {}
      });
      return Array.from(results);
    });

    log(`Found ${stores.length} stores from Shopify examples`);
    stores.forEach(domain => {
      addLead(domain, 'Shopify-Examples');
    });

  } catch (error) {
    addError('Showcase', 'Failed to scrape Shopify examples', error.message);
  } finally {
    await context.close();
  }
}

// 4. Enrich domain data
async function enrichDomains(browser, limit = 50) {
  log(`Starting enrichment for up to ${limit} domains...`);

  const domainsToEnrich = results.leads.slice(0, limit);
  results.stats.enrichment.attempted = domainsToEnrich.length;

  for (let i = 0; i < domainsToEnrich.length; i++) {
    const lead = domainsToEnrich[i];
    log(`Enriching ${i + 1}/${domainsToEnrich.length}: ${lead.domain}`);

    const context = await browser.newContext({
      userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
    });
    const page = await context.newPage();

    try {
      const url = lead.domain.startsWith('http') ? lead.domain : `https://${lead.domain}`;

      await page.goto(url, { 
        waitUntil: 'domcontentloaded',
        timeout: 15000 
      });

      await page.waitForTimeout(1000);

      const data = await page.evaluate(() => {
        // Extract title
        const title = document.title || '';

        // Look for brand name
        let brandName = title.split(/[|-]/)[0].trim();
        if (!brandName) {
          const h1 = document.querySelector('h1');
          brandName = h1?.textContent?.trim() || '';
        }

        // Guess category from content
        const bodyText = document.body.innerText.toLowerCase();
        let category = 'Unknown';

        if (bodyText.includes('fashion') || bodyText.includes('clothing') || bodyText.includes('apparel')) {
          category = 'Fashion/Apparel';
        } else if (bodyText.includes('beauty') || bodyText.includes('cosmetic') || bodyText.includes('skincare')) {
          category = 'Beauty/Cosmetics';
        } else if (bodyText.includes('jewelry') || bodyText.includes('jewellery')) {
          category = 'Jewelry';
        } else if (bodyText.includes('home') || bodyText.includes('furniture') || bodyText.includes('decor')) {
          category = 'Home/Furniture';
        } else if (bodyText.includes('electronics') || bodyText.includes('tech') || bodyText.includes('gadget')) {
          category = 'Electronics';
        } else if (bodyText.includes('food') || bodyText.includes('beverage') || bodyText.includes('coffee')) {
          category = 'Food/Beverage';
        } else if (bodyText.includes('fitness') || bodyText.includes('sport') || bodyText.includes('athletic')) {
          category = 'Sports/Fitness';
        } else if (bodyText.includes('pet') || bodyText.includes('dog') || bodyText.includes('cat')) {
          category = 'Pet Products';
        }

        // Check if site looks active
        const hasProducts = document.querySelectorAll('[class*="product"]').length > 0;
        const hasCart = document.querySelector('[class*="cart"], [href*="cart"]') !== null;
        const active = (hasProducts || hasCart) ? 'Yes' : 'Maybe';

        return { brandName, category, active };
      });

      lead.brandName = data.brandName || lead.domain.split('.')[0];
      lead.category = data.category;
      lead.active = data.active;

      results.stats.enrichment.success++;

    } catch (error) {
      lead.notes = `Enrichment failed: ${error.message}`;
      addError('Enrichment', `Failed to enrich ${lead.domain}`, error.message);
      results.stats.enrichment.errors++;
    } finally {
      await context.close();
    }

    // Small delay between requests
    await new Promise(resolve => setTimeout(resolve, 500));
  }
}

// 5. Generate outputs
function generateCSV() {
  log('Generating CSV output...');

  const headers = ['Domain', 'Brand Name', 'Category', 'Active', 'Source', 'Notes'];
  const rows = results.leads.map(lead => [
    lead.domain,
    lead.brandName || '',
    lead.category || '',
    lead.active || 'Unknown',
    lead.sources.join(', '),
    lead.notes || ''
  ]);

  const csv = [
    headers.join(','),
    ...rows.map(row => row.map(cell => {
      // Escape commas and quotes
      const escaped = String(cell).replace(/"/g, '""');
      return escaped.includes(',') ? `"${escaped}"` : escaped;
    }).join(','))
  ].join('\n');

  fs.writeFileSync(CSV_OUTPUT, csv);
  log(`CSV written to ${CSV_OUTPUT} with ${results.leads.length} leads`);
}

function generateReport() {
  log('Generating scraping report...');

  const report = `# Shopify Plus Lead Generation Report

**Generated:** ${new Date().toISOString()}

## Summary

- **Total Leads Collected:** ${results.leads.length}
- **Sources:** ${[...new Set(results.leads.flatMap(l => l.sources))].join(', ')}
- **Total Errors:** ${results.errors.length}

## Statistics by Source

### BuiltWith
- Attempted: ${results.stats.builtwith.attempted ? 'Yes' : 'No'}
- Domains Found: ${results.stats.builtwith.success}
- Errors: ${results.stats.builtwith.errors}

### Shopify App Store
- Attempted: ${results.stats.appStore.attempted ? 'Yes' : 'No'}
- Stores Found: ${results.stats.appStore.success}
- Errors: ${results.stats.appStore.errors}

### Domain Enrichment
- Attempted: ${results.stats.enrichment.attempted}
- Successful: ${results.stats.enrichment.success}
- Failed: ${results.stats.enrichment.errors}

## What Worked

${results.leads.length > 0 ? `Successfully collected ${results.leads.length} leads from various sources.` : 'Limited success in data collection.'}

${results.stats.builtwith.success > 0 ? `- BuiltWith provided ${results.stats.builtwith.success} domains\n` : ''}
${results.stats.appStore.success > 0 ? `- App Store scraping found ${results.stats.appStore.success} stores\n` : ''}
${results.stats.enrichment.success > 0 ? `- Successfully enriched ${results.stats.enrichment.success} domains\n` : ''}

## What Failed

${results.errors.length === 0 ? 'No significant errors encountered.' : ''}

${results.errors.map((err, i) => `${i + 1}. **${err.source}**: ${err.message}
   - Details: ${err.details || 'N/A'}
   - Time: ${err.timestamp}
`).join('\n')}

## Lead Quality

${results.leads.length > 0 ? `
- Domains with brand names: ${results.leads.filter(l => l.brandName).length}
- Domains with category: ${results.leads.filter(l => l.category && l.category !== 'Unknown').length}
- Active sites: ${results.leads.filter(l => l.active === 'Yes').length}
` : 'Insufficient data for quality metrics.'}

## Recommendations

${results.stats.builtwith.errors > 0 ? '- BuiltWith scraping encountered issues - may need alternative approach or manual verification\n' : ''}
${results.stats.appStore.errors > 0 ? '- App Store scraping had limited success - consider alternative review platforms\n' : ''}
${results.leads.length < 20 ? '- Total lead count below target - recommend expanding to additional sources\n' : ''}
${results.stats.enrichment.errors > results.stats.enrichment.success ? '- High enrichment failure rate - many domains may be unreachable\n' : ''}

## Next Steps

1. Manually verify the collected leads
2. Consider additional sources: 
   - Commerce.js directories
   - SimilarWeb
   - Manual LinkedIn/Google searches
3. Focus on working domains for outreach
4. Consider paid access to BuiltWith or similar services for better data

## Files Generated

- \`shopify-leads-raw.json\` - Raw collected data
- \`shopify-plus-leads.csv\` - Formatted lead list
- \`screenshots/\` - Debugging screenshots
`;

  fs.writeFileSync(REPORT_OUTPUT, report);
  log(`Report written to ${REPORT_OUTPUT}`);
}

// Main execution
async function main() {
  log('Starting Shopify Plus lead generation pipeline...');

  // Ensure directories exist
  fs.mkdirSync(SCREENSHOTS_DIR, { recursive: true });

  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-setuid-sandbox']
  });

  try {
    // Step 1: Try BuiltWith
    await scrapeBuiltWith(browser);

    // Step 2: Scrape App Store
    const apps = [
      { name: 'Loox', slug: 'loox' },
      { name: 'Stamped.io', slug: 'stamped-product-reviews-ugc' },
      { name: 'Judge.me', slug: 'judgeme-product-reviews' }
    ];

    for (const app of apps) {
      await scrapeAppStore(browser, app.name, app.slug);
    }

    // Step 3: Try Shopify showcase as backup
    if (results.leads.length < 10) {
      log('Low lead count - trying Shopify examples as backup...');
      await scrapeShopifyShowcase(browser);
    }

    // Save raw data
    fs.writeFileSync(RAW_JSON, JSON.stringify(results, null, 2));
    log(`Raw data saved to ${RAW_JSON}`);

    // Step 4: Enrich domains
    if (results.leads.length > 0) {
      await enrichDomains(browser, 50);
    }

    // Step 5: Generate outputs
    generateCSV();
    generateReport();

    log(`\n=== PIPELINE COMPLETE ===`);
    log(`Total leads collected: ${results.leads.length}`);
    log(`Total errors: ${results.errors.length}`);
    log(`Check ${DATA_DIR} for all outputs`);

  } catch (error) {
    log(`FATAL ERROR: ${error.message}`);
    addError('Pipeline', 'Fatal error in main execution', error.stack);
  } finally {
    await browser.close();
  }
}

// Run it
main().catch(console.error);

