const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

const DATA_DIR = path.join(__dirname, '../data');
const RAW_JSON = path.join(DATA_DIR, 'shopify-leads-raw.json');
const CSV_OUTPUT = path.join(DATA_DIR, 'shopify-plus-leads.csv');
const SCREENSHOTS_DIR = path.join(DATA_DIR, 'screenshots');

// Load existing data
const existingData = JSON.parse(fs.readFileSync(RAW_JSON, 'utf-8'));

// Filter out social media and non-store domains
const socialMediaDomains = [
  'x.com', 'twitter.com', 'linkedin.com', 'facebook.com', 'instagram.com',
  'tiktok.com', 'threads.net', 'vimeo.com', 'youtube.com', 'github.com',
  'pinterest.com', 'snapchat.com', 'reddit.com'
];

const filteredLeads = existingData.leads.filter(lead => 
  !socialMediaDomains.includes(lead.domain)
);

console.log(`Filtered from ${existingData.leads.length} to ${filteredLeads.length} leads`);

// Function to scrape additional sources
async function scrapeAdditionalSources(browser) {
  const newLeads = [];

  // 1. Try Commerce Inspector or similar
  console.log('Trying alternative Shopify directories...');

  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
  });
  const page = await context.newPage();

  // Try myip.ms Shopify sites
  try {
    console.log('Scraping myip.ms Shopify hosting list...');
    await page.goto('https://myip.ms/browse/sites/1/own/376714', {
      waitUntil: 'domcontentloaded',
      timeout: 30000
    });

    await page.waitForTimeout(2000);
    await page.screenshot({ 
      path: path.join(SCREENSHOTS_DIR, 'myip-shopify.png'),
      fullPage: false
    });

    const domains = await page.evaluate(() => {
      const results = [];
      document.querySelectorAll('a[href*="//"]').forEach(el => {
        const text = el.textContent?.trim();
        const href = el.href;

        if (text && text.match(/^[a-z0-9-]+\.[a-z]{2,}/i) && !text.includes('myip.ms')) {
          results.push(text.toLowerCase().replace('www.', ''));
        }

        if (href) {
          try {
            const url = new URL(href);
            const hostname = url.hostname.replace('www.', '');
            if (!hostname.includes('myip.ms') && !hostname.includes('shopify.com')) {
              results.push(hostname);
            }
          } catch (e) {}
        }
