];

// Filter function
function isValidStoreDomain(domain) {
  // Exclude exact matches
  if (excludeDomains.includes(domain.toLowerCase())) {
    return false;
  }

  // Exclude Shopify infrastructure domains
  if (domain.includes('shopify.') && !domain.includes('.myshopify.com')) {
    return false;
  }

  // Exclude domains that are clearly not stores
  if (domain.includes('academy') || 
      domain.includes('status') || 
      domain.includes('dev.') ||
      domain.includes('api.')) {
    return false;
  }

  // Exclude social media subdomains
  const socialKeywords = ['facebook', 'twitter', 'instagram', 'linkedin', 'tiktok', 'youtube'];
  if (socialKeywords.some(keyword => domain.includes(keyword))) {
    return false;
  }

  return true;
}

