        } else if (bodyText.includes('electronics') || bodyText.includes('tech') || bodyText.includes('gadget')) {
          category = 'Electronics';
        } else if (bodyText.includes('food') || bodyText.includes('beverage') || bodyText.includes('coffee') || bodyText.includes('drink')) {
          category = 'Food/Beverage';
        } else if (bodyText.includes('fitness') || bodyText.includes('sport') || bodyText.includes('athletic') || bodyText.includes('gym')) {
          category = 'Sports/Fitness';
        } else if (bodyText.includes('pet') || bodyText.includes('dog') || bodyText.includes('cat')) {
          category = 'Pet Products';
        } else if (bodyText.includes('supplement') || bodyText.includes('vitamin') || bodyText.includes('health')) {
          category = 'Health/Wellness';
        }

        // Check if site is active
        const hasProducts = document.querySelectorAll('[class*="product"], [class*="item"]').length > 5;
        const hasCart = document.querySelector('[class*="cart"], [href*="cart"], [class*="bag"]') !== null;
        const hasPrices = document.body.innerHTML.includes('$') || document.body.innerHTML.includes('€') || document.body.innerHTML.includes('£');

        let active = 'Unknown';
        if ((hasProducts && hasPrices) || hasCart) {
          active = 'Yes';
        } else if (hasProducts || hasPrices) {
          active = 'Maybe';
        }

        return { brandName, category, active };
      });

      // Update lead
      lead.brandName = enrichmentData.brandName || lead.domain.split('.')[0].toUpperCase();
      lead.category = enrichmentData.category;
      lead.active = enrichmentData.active;
      lead.notes = lead.notes || '';

      enriched++;

    } catch (error) {
      lead.brandName = lead.brandName || lead.domain.split('.')[0].toUpperCase();
      lead.category = lead.category || 'Unknown';
      lead.active = 'Unknown';
      lead.notes = `Enrichment failed: ${error.message.substring(0, 50)}`;
      failed++;
    } finally {
      await context.close();
    }

    // Save progress every 10 leads
    if ((i + 1) % 10 === 0) {
      fs.writeFileSync(RAW_JSON, JSON.stringify(data, null, 2));
      console.log(`Progress saved (${enriched} enriched, ${failed} failed)`);
    }

    await new Promise(resolve => setTimeout(resolve, 500));
  }

  await browser.close();

  return { enriched, failed };
}

