const fs = require('fs');
const path = require('path');
const { chromium } = require('playwright');

const DATA_DIR = path.join(__dirname, '../data');
const RAW_JSON = path.join(DATA_DIR, 'shopify-leads-raw.json');
const CSV_OUTPUT = path.join(DATA_DIR, 'shopify-plus-leads.csv');

const data = JSON.parse(fs.readFileSync(RAW_JSON, 'utf-8'));
console.log(`Starting enrichment for ${data.leads.length} leads...`);

async function enrichAllLeads() {
  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-setuid-sandbox']
  });

  let enriched = 0;
  let failed = 0;

  for (let i = 0; i < data.leads.length; i++) {
    const lead = data.leads[i];

    if (lead.brandName && lead.category && lead.category !== 'Unknown') {
      continue;
    }

    console.log(`${i + 1}/${data.leads.length}: ${lead.domain}`);

    const context = await browser.newContext({
      userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
    });
    const page = await context.newPage();

    try {
      const url = lead.domain.startsWith('http') ? lead.domain : `https://${lead.domain}`;
      await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 10000 });
      await page.waitForTimeout(1000);

      const data = await page.evaluate(() => {
        const title = document.title || '';
        let brandName = title.split(/[|-]/)[0].trim();

        if (!brandName || brandName.length < 3) {
          const h1 = document.querySelector('h1');
          if (h1) brandName = h1.textContent?.trim() || '';
        }

        const bodyText = document.body.innerText.toLowerCase();
        let category = 'General';

        if (bodyText.includes('fashion') || bodyText.includes('clothing') || bodyText.includes('apparel')) {
          category = 'Fashion/Apparel';
        } else if (bodyText.includes('beauty') || bodyText.includes('cosmetic') || bodyText.includes('skincare')) {
          category = 'Beauty/Cosmetics';
        } else if (bodyText.includes('jewelry')) {
          category = 'Jewelry';
        } else if (bodyText.includes('home') || bodyText.includes('furniture') || bodyText.includes('decor')) {
          category = 'Home/Furniture';
        } else if (bodyText.includes('electronics') || bodyText.includes('tech')) {
          category = 'Electronics';
        } else if (bodyText.includes('food') || bodyText.includes('beverage') || bodyText.includes('coffee')) {
          category = 'Food/Beverage';
        } else if (bodyText.includes('fitness') || bodyText.includes('sport') || bodyText.includes('athletic')) {
          category = 'Sports/Fitness';
        } else if (bodyText.includes('pet') || bodyText.includes('dog') || bodyText.includes('cat')) {
          category = 'Pet Products';
        } else if (bodyText.includes('supplement') || bodyText.includes('vitamin') || bodyText.includes('health')) {
          category = 'Health/Wellness';
        }

        const hasProducts = document.querySelectorAll('[class*="product"]').length > 5;
        const hasCart = document.querySelector('[class*="cart"], [href*="cart"]') !== null;
        const hasPrices = document.body.innerHTML.includes('$') || document.body.innerHTML.includes('€');

        let active = 'Unknown';
        if ((hasProducts && hasPrices) || hasCart) {
          active = 'Yes';
        } else if (hasProducts || hasPrices) {
          active = 'Maybe';
        }

        return { brandName, category, active };
      });

      lead.brandName = data.brandName || lead.domain.split('.')[0].toUpperCase();
      lead.category = data.category;
      lead.active = data.active;
      enriched++;

    } catch (error) {
      lead.brandName = lead.brandName || lead.domain.split('.')[0].toUpperCase();
      lead.category = lead.category || 'Unknown';
      lead.active = 'Unknown';
      lead.notes = (lead.notes || '') + ' ' + error.message.substring(0, 40);
      failed++;
    } finally {
      await context.close();
    }

    if ((i + 1) % 10 === 0) {
      fs.writeFileSync(RAW_JSON, JSON.stringify(data, null, 2));
    }

    await new Promise(resolve => setTimeout(resolve, 500));
  }

  await browser.close();
  return { enriched, failed };
}

async function main() {
  const stats = await enrichAllLeads();

  fs.writeFileSync(RAW_JSON, JSON.stringify(data, null, 2));
  console.log(`\nEnrichment complete: ${stats.enriched} enriched, ${stats.failed} failed`);

  // Generate CSV
  const headers = ['Domain', 'Brand Name', 'Category', 'Active', 'Source', 'Notes'];
  const rows = data.leads.map(lead => [
    lead.domain,
    lead.brandName || '',
    lead.category || 'Unknown',
    lead.active || 'Unknown',
    lead.sources.join('; '),
    (lead.notes || '').replace(/\n/g, ' ')
  ]);

  const csv = [
    headers.join(','),
    ...rows.map(row => row.map(cell => {
      const escaped = String(cell).replace(/"/g, '""');
      return escaped.includes(',') || escaped.includes(';') ? `"${escaped}"` : escaped;
    }).join(','))
  ].join('\n');

  fs.writeFileSync(CSV_OUTPUT, csv);

  // Stats
  const enrichedCount = data.leads.filter(l => l.brandName && l.brandName !== '').length;
  const categorizedCount = data.leads.filter(l => l.category && l.category !== 'Unknown').length;
  const activeCount = data.leads.filter(l => l.active === 'Yes').length;

  const byCategory = {};
  const bySource = {};

  data.leads.forEach(lead => {
    const cat = lead.category || 'Unknown';
    byCategory[cat] = (byCategory[cat] || 0) + 1;
    lead.sources.forEach(source => {
      bySource[source] = (bySource[source] || 0) + 1;
    });
  });

  console.log('\n=== STATISTICS ===');
  console.log(`Total: ${data.leads.length}`);
  console.log(`Enriched: ${enrichedCount}`);
  console.log(`Categorized: ${categorizedCount}`);
  console.log(`Active: ${activeCount}`);

  console.log('\nBy Category:');
  Object.entries(byCategory)
    .sort((a, b) => b[1] - a[1])
    .forEach(([cat, count]) => console.log(`  ${cat}: ${count}`));

  console.log('\nBy Source:');
  Object.entries(bySource)
    .sort((a, b) => b[1] - a[1])
    .forEach(([source, count]) => console.log(`  ${source}: ${count}`));

  console.log(`\n✅ Done! Files in ${DATA_DIR}/`);
}

